import React from "react"
import "./TOC.css"

function foo(items, level) {
	return(
		<React.Fragment>
		{items &&
			items.map((item, i) => {
				return(
				<React.Fragment key={item + "-" + i}>
					<a href={item.url} aria-label="url"><div className={`toc-${level}`}><div dangerouslySetInnerHTML={{__html: item.title}} /></div></a>
					{item.items && foo(item.items, level+1)}
				</React.Fragment>
				)
			})
		}
		</React.Fragment>
	)
}

export default function TOC({ data, title }) {

	return(
		<div className="toc" id="toc">
			<a href="#top" aria-label="url"><div className="toc-0 yay">{title}</div></a>
			{foo(data.items, 1)}
		</div>
	)

}