import React from "react"
import { graphql, Link } from "gatsby"
import { MDXRenderer } from "gatsby-plugin-mdx"
import Layout from "../components/Layout"
import PostHeader from "../components/PostHeader"
import TOC from "../components/TOC"
import SEO from "../components/SEO"
import { DiscussionEmbed } from "disqus-react"
import useDarkMode from 'use-dark-mode';
import "../styles/post.css"

function getCoords(elem) { // crossbrowser version
	const box = elem.getBoundingClientRect();
	const body = document.body;
	const docEl = document.documentElement;
	const scrollTop = window.pageYOffset || docEl.scrollTop || body.scrollTop;
	const clientTop = docEl.clientTop || body.clientTop || 0;
	const top = box.top +  scrollTop - clientTop;
	return Math.round(top);
}

export default function PageTemplate({ data: { mdx }, pageContext }) {

	const darkMode = useDarkMode(false)
	const [disqusDark, setDisqusDark] = React.useState(false)
	
	React.useEffect(() => {
		setTimeout(() => setDisqusDark(darkMode.value), 400)
		// delay so that the background gets to adjust before updating disqus
	}, [darkMode.value])

	React.useEffect(() => {

		const toc = document.getElementById('toc').children

		setTimeout(() => {
			const headings = Array.from(document.querySelectorAll(".post-title,h1,h2"))
			const cutoffs = headings.map(y => getCoords(y))
			window.addEventListener('scroll', function() {
				// console.log('scroll => ', window.pageYOffset)
				let i = -1
				for (i = 0; i < cutoffs.length; i ++) {
					if (window.pageYOffset + (window.innerHeight / 5) < cutoffs[i]) {
						i = Math.max(i - 1, 0)
						// console.log(headings[i].innerText, cutoffs[i])
						break
					}
				}
				for (let j = 0; j < toc.length; j ++) {
					toc[j].children[0].classList.remove('yay')
				}
				toc[Math.min(i, toc.length - 1)].children[0].classList.add('yay')

			});
		}, 1000)

	}, [])

	const disqusConfig = {
		shortname: `artt-github-io`,
		config: { identifier: mdx.fields.slug },
	}

	return (
		<Layout>
			<SEO
				title={mdx.frontmatter.title}
				pathname={mdx.fields.slug}
				description={mdx.frontmatter.excerpt}
				image={mdx.frontmatter.image && mdx.frontmatter.image.publicURL}
			/>
			<div />
			<div className="content">
				<PostHeader frontmatter={mdx.frontmatter} timeToRead={mdx.timeToRead} showLang showTags/>
				<MDXRenderer>{mdx.body}</MDXRenderer>
				<div className="postnav">
					{pageContext.previous &&
						<div>
							<Link to={pageContext.previous.slug} className="postnav-previous">
								<div className="postnav-direction">‹ previous</div>
								<div className="postnav-title">{pageContext.previous.title}</div>
							</Link>
						</div>
					}
					<div className="filler" />
					{pageContext.next &&
						<div>
							<Link to={pageContext.next.slug} className="postnav-next">
								<div className="postnav-direction">next ›</div>
								<div className="postnav-title">{pageContext.next.title}</div>
							</Link>
						</div>
					}
				</div>
				<DiscussionEmbed {...disqusConfig} className="disqus" theme={String(disqusDark)} />
			</div>
			<TOC data={mdx.tableOfContents} title={mdx.frontmatter.title} />
		</Layout>
	)
}

export const pageQuery = graphql`
	query BlogPostQuery($id: String) {
		mdx(id: { eq: $id }) {
			id
			body
			fields {
				slug
			}
			frontmatter {
				title
				date(formatString: "YYYY.MM.DD")
				tags
				lang
				excerpt
				image {
					publicURL
					childImageSharp {
						fluid(maxWidth: 840) {
              ...GatsbyImageSharpFluid
            }
					}
				}
				showimage
			}
			timeToRead
			tableOfContents(maxDepth: 2)
		}
	}
`